int main(int argc, char const *argv[]) {
  RSource plugin;
  json output, params;

  // Set example values to params
  params["use_renv"] = true;
  params["init_script"] = "source.R";

  // Set the parameters
  plugin.set_params(params);

  // Process data
  plugin.get_output(output);
  cout << "Output: " << output << endl;
  plugin.get_output(output);
  cout << "Output: " << output << endl;
  plugin.get_output(output);
  cout << "Output: " << output << endl;
  plugin.get_output(output);
  cout << "Output: " << output << endl;

  return 0;
}
